&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;&lt;strong&gt;Responsibilities&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Manage on average 60-80 incoming and outgoing patient calls daily regarding medical bills&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Utilize the Cedar platform to handle all patient questions via inbound chats, phone calls and perform appropriate outbound call campaign&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Run and follow through on escalations to the healthcare provider&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Lead the payment posting process and follow up on defaulted payments&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Appropriately follow up with insurance and other third parties&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Meet assigned team and individual metrics related to satisfaction and collections performance&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
